let LOYALTY_CONFIG=null,USER_LOYALTY=null;export async function initLoyaltySystem(){return await loadLoyaltyConfig(),loadUserLoyalty(),{config:LOYALTY_CONFIG,user:USER_LOYALTY}}async function loadLoyaltyConfig(){try{const e=await fetch("data/loyalty-config.json");LOYALTY_CONFIG=await e.json()}catch(e){LOYALTY_CONFIG=getDefaultLoyaltyConfig()}}function getDefaultLoyaltyConfig(){return{programName:"F&B Loyalty Club",tiers:[{id:"dong",name:"Thành Viên Đồng",icon:"🥉",minPoints:0,multiplier:1},{id:"bac",name:"Thành Viên Bạc",icon:"🥈",minPoints:5e3,multiplier:1.5},{id:"vang",name:"Thành Viên Vàng",icon:"🥇",minPoints:15e3,multiplier:2},{id:"kimcuong",name:"Thành Viên Kim Cương",icon:"💎",minPoints:5e4,multiplier:3}],rewards:[],earningRules:{baseRate:{amount:1e4,points:1}}}}function loadUserLoyalty(){const e=localStorage.getItem("fnb_loyalty_user");e?USER_LOYALTY=JSON.parse(e):(USER_LOYALTY={memberId:generateMemberId(),joinedDate:(new Date).toISOString(),totalPoints:0,availablePoints:0,lifetimePoints:0,tierId:"dong",tierProgress:0,nextTierPoints:5e3,transactions:[],rewards:[],referrals:[]},saveUserLoyalty())}function saveUserLoyalty(){localStorage.setItem("fnb_loyalty_user",JSON.stringify(USER_LOYALTY))}function generateMemberId(){return`FNB${Date.now().toString(36).toUpperCase()}${Math.random().toString(36).substr(2,4).toUpperCase()}`}export function getCurrentTier(){const e=USER_LOYALTY.lifetimePoints;let t=LOYALTY_CONFIG.tiers[0];for(const r of LOYALTY_CONFIG.tiers){if(!(e>=r.minPoints))break;t=r}return t}export function getNextTier(){const e=getCurrentTier(),t=LOYALTY_CONFIG.tiers.findIndex(t=>t.id===e.id);return t<LOYALTY_CONFIG.tiers.length-1?LOYALTY_CONFIG.tiers[t+1]:null}export function getTierProgress(){const e=getCurrentTier(),t=getNextTier(),r=USER_LOYALTY.lifetimePoints;if(!t)return{percent:100,current:r,needed:0,isMaxTier:!0};const n=e.minPoints,i=t.minPoints-n,a=r-n;return{percent:Math.min(100,Math.round(a/i*100)),current:r,needed:t.minPoints-r,nextTierName:t.name,isMaxTier:!1}}export function calculatePointsEarned(e){const t=getCurrentTier(),r=LOYALTY_CONFIG.earningRules.baseRate,n=Math.floor(e/r.amount)*r.points,i=Math.floor(n*(t.multiplier-1));return{basePoints:n,tierBonus:i,totalPoints:n+i,tier:t.name,multiplier:t.multiplier}}export function addPointsFromPurchase(e,t={}){const r=calculatePointsEarned(e),n=(new Date).toISOString();USER_LOYALTY.transactions.push({id:`txn_${Date.now()}`,type:"earned",source:"purchase",points:r.totalPoints,basePoints:r.basePoints,bonusPoints:r.tierBonus,orderTotal:e,tier:USER_LOYALTY.tierId,timestamp:n,description:`Mua hàng ${formatCurrency(e)}`}),USER_LOYALTY.totalPoints+=r.totalPoints,USER_LOYALTY.availablePoints+=r.totalPoints,USER_LOYALTY.lifetimePoints+=r.totalPoints;const i=checkTierUpgrade();return saveUserLoyalty(),{...r,newBalance:USER_LOYALTY.availablePoints,tierUpgraded:i}}function checkTierUpgrade(){const e=getCurrentTier(),t=e.id;if(t!==USER_LOYALTY.tierId){const r=LOYALTY_CONFIG.tiers.find(e=>e.id===USER_LOYALTY.tierId);return USER_LOYALTY.tierId=t,USER_LOYALTY.transactions.push({id:`tier_upgrade_${Date.now()}`,type:"tier_upgrade",fromTier:r?.name,toTier:e.name,timestamp:(new Date).toISOString(),description:`Nâng hạng lên ${e.name}`}),e.birthdayBonus&&(USER_LOYALTY.transactions.push({id:`tier_bonus_${Date.now()}`,type:"earned",source:"tier_upgrade_bonus",points:e.birthdayBonus,timestamp:(new Date).toISOString(),description:`Bonus nâng hạng: ${e.birthdayBonus} points`}),USER_LOYALTY.availablePoints+=e.birthdayBonus),saveUserLoyalty(),{upgraded:!0,newTier:e,oldTier:r}}return{upgraded:!1}}export function redeemReward(e){const t=LOYALTY_CONFIG.rewards.find(t=>t.id===e);if(!t)return{success:!1,error:"Không tìm thấy reward"};if(USER_LOYALTY.availablePoints<t.points)return{success:!1,error:"Không đủ points",needed:t.points-USER_LOYALTY.availablePoints};USER_LOYALTY.availablePoints-=t.points;const r={id:`redemption_${Date.now()}`,rewardId:t.id,rewardName:t.name,pointsSpent:t.points,status:"active",redeemedAt:(new Date).toISOString(),expiresAt:new Date(Date.now()+24*t.expiryDays*60*60*1e3).toISOString(),terms:t.terms};return USER_LOYALTY.rewards.push(r),USER_LOYALTY.transactions.push({id:`txn_redeem_${Date.now()}`,type:"redeemed",rewardId:t.id,rewardName:t.name,points:-t.points,timestamp:(new Date).toISOString(),description:`Đổi thưởng: ${t.name}`}),saveUserLoyalty(),{success:!0,redemption:r,newBalance:USER_LOYALTY.availablePoints}}export function getAvailableRewards(e=null){let t=LOYALTY_CONFIG.rewards;return e&&(t=t.filter(t=>t.category===e)),t.map(e=>({...e,canAfford:USER_LOYALTY.availablePoints>=e.points,progress:Math.min(100,Math.round(USER_LOYALTY.availablePoints/e.points*100))}))}export function getTransactionHistory(e=20){return[...USER_LOYALTY.transactions].sort((e,t)=>new Date(t.timestamp)-new Date(e.timestamp)).slice(0,e)}export function getRedemptionHistory(){return[...USER_LOYALTY.rewards].sort((e,t)=>new Date(t.redeemedAt)-new Date(e.redeemedAt))}export function addReferral(e){const t=LOYALTY_CONFIG.settings?.referralBonusBoth||200;return USER_LOYALTY.referrals.some(t=>t.code===e)?{success:!1,error:"Đã sử dụng mã giới thiệu này"}:(USER_LOYALTY.referrals.push({code:e,joinedAt:(new Date).toISOString(),status:"pending"}),USER_LOYALTY.transactions.push({id:`referral_${Date.now()}`,type:"earned",source:"referral",points:t,timestamp:(new Date).toISOString(),description:"Bonus giới thiệu bạn bè"}),USER_LOYALTY.availablePoints+=t,USER_LOYALTY.lifetimePoints+=t,saveUserLoyalty(),{success:!0,points:t,newBalance:USER_LOYALTY.availablePoints})}export function generateReferralCode(){const e=USER_LOYALTY.memberId,t=Math.random().toString(36).substr(2,3).toUpperCase();return`FNB-${e.slice(-4)}-${t}`}export function getUserLoyaltySummary(){const e=getCurrentTier(),t=getTierProgress();return{memberId:USER_LOYALTY.memberId,tier:e,availablePoints:USER_LOYALTY.availablePoints,lifetimePoints:USER_LOYALTY.lifetimePoints,tierProgress:t,totalRewards:USER_LOYALTY.rewards.length,activeRewards:USER_LOYALTY.rewards.filter(e=>"active"===e.status).length}}function formatCurrency(e){return new Intl.NumberFormat("vi-VN",{style:"currency",currency:"VND"}).format(e)}export function resetUserLoyalty(){return localStorage.removeItem("fnb_loyalty_user"),loadUserLoyalty(),USER_LOYALTY}window.LoyaltySystem={init:initLoyaltySystem,getCurrentTier:getCurrentTier,getNextTier:getNextTier,getTierProgress:getTierProgress,calculatePointsEarned:calculatePointsEarned,addPointsFromPurchase:addPointsFromPurchase,redeemReward:redeemReward,getAvailableRewards:getAvailableRewards,getTransactionHistory:getTransactionHistory,getRedemptionHistory:getRedemptionHistory,getUserLoyaltySummary:getUserLoyaltySummary,addReferral:addReferral,generateReferralCode:generateReferralCode,resetUserLoyalty:resetUserLoyalty};